var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"용이 되어야 해.","JPN":"龍にならないと。","ENG":"I must become a Dragon.","TWN":"一定要變成龍！"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"용이 되지 않으면 이 고통에서 벗어날 수 없어.","JPN":"龍にならなければ、この苦痛から抜け出せない。","ENG":"I cannot escape this suffering unless I become a Dragon.","TWN":"不變成龍就無法擺脫痛苦。"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"시윤아.","JPN":"シリュウ。","ENG":"My dear Shiyoon.","TWN":"時雲，"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마가 용이 되려면 용의 피가 더 필요하단다.","JPN":"お母さんが龍になるためには龍の血がもっと必要なの。","ENG":"Mommy needs more Dragon Blood to become a Dragon.","TWN":"媽媽還需要更多的龍血才能變成龍。"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 시윤이는 착하니까…… 엄마한테 줄 거지?","JPN":"シリュウはいい子だから……お母さんにくれるわよね？","ENG":"You're a good boy… You'll help mommy out, right?","TWN":"我們時雲這麼乖……一定會把血給媽媽的吧？"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까…… 그러니까……","JPN":"だから……だから……","ENG":"Okay then…","TWN":"所以……所以……"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>네 피를 내놔!</color>","JPN":"<color=#ff3636>お前の血をよこせ！</color>","ENG":"<color=#ff3636>Give me your blood!</color>","TWN":"<color=#ff3636>把血給我！</color>"},"stage":{"bg":"MAINSTREAM_7050010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……허억!","JPN":"……はっ！","ENG":"…Gaah!","TWN":"……嚇！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하아…… 하아……","JPN":"はあ……はあ……","ENG":"Huff, huff...","TWN":"呼呼……呼呼……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……자면서 계속 소리를 지르더군.","JPN":"……何度もうなされていたようだな。","ENG":"…You kept screaming in your sleep.","TWN":"……你一直說夢話。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"요즘도 계속 악몽을 꾸나?","JPN":"最近もずっと悪夢を見ているのか？","ENG":"Do you still have nightmares?","TWN":"最近還是很常做惡夢嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네…….","JPN":"はい……","ENG":"Yes…","TWN":"嗯……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저, 용혈이란 게 뭐죠?","JPN":"あの、龍血とは何ですか？","ENG":"Um, what is this \\"Dragon Blood?\\"","TWN":"那個，龍血是什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그 말은 또 어디서 들었지?","JPN":"……それをどこで聞いた？","ENG":"…Where did you hear about that?","TWN":"……這個詞你從哪裡聽來的？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"엄마가…… 계속 그 이야기를 했었어요.","JPN":"お母さんが……ずっとその話をしていました。","ENG":"My mom… She never stopped talking about it.","TWN":"我媽媽……從以前就一直提到龍血。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 몸에 있는 용혈이 필요하다고…… 용이 되어야 한다고.","JPN":"僕の体にある龍血が必要で……龍にならなければならない、と。","ENG":"She said she needs Dragon Blood from me… That she needs to become a Dragon.","TWN":"說他需要我體內的龍血……說她一定要變成龍。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용이 되면 좋은 건가요? 용이 대체 뭐죠?","JPN":"龍になるのはいいことですか？　龍っていったい何ですか？","ENG":"Is becoming a Dragon a good thing? What does that even mean, to become a Dragon?","TWN":"變成龍很好嗎？龍到底是什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>인간이 아닌 것</color>이지.","JPN":"……<color=#ffd34c>人ならざるモノ</color>だ。","ENG":"…It means you're <color=#ffd34c>no longer human</color>.","TWN":"……<color=#ffd34c>總之不是人</color>。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 용이 되고 싶으냐, 꼬마야?","JPN":"お前は龍になりたいのか、チビ？","ENG":"Do you want to become a Dragon, kid?","TWN":"小鬼，你想變成龍嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……잘 모르겠어요.","JPN":"……よくわかりません。","ENG":"...I'm not sure.","TWN":"……我也不知道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 엄마가 그렇게 용이 되고 싶어했으니까…… 좋은 거 아닐까요?","JPN":"でも、お母さんがあれほど龍になりたがっていたから……いいものじゃないでしょうか？","ENG":"But if mom wanted to become a Dragon so badly… maybe it's a good thing?","TWN":"可是我媽媽這麼想變成龍……那變成龍應該很好吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"누군가에게는 그럴지도 모르지.","JPN":"誰かにとってはそうかもしれん。","ENG":"Perhaps to some.","TWN":"對某些人來說或許是，"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 네가 용이 되면, 난 너를 죽일 거다.","JPN":"しかしお前が龍になるなら、私はお前を殺す。","ENG":"But if you become a Dragon, I will kill you.","TWN":"但如果你變成龍，我就會殺了你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네……? 왜, 왜요?","JPN":"え……？　ど、どうしてですか？","ENG":"Huh…? W-why?","TWN":"蛤……？為什麼要殺我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"말해 줄 수 없어.","JPN":"それは言えない。","ENG":"I can't tell you why.","TWN":"我不能告訴你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"용혈과 용에 대해 알아갈수록, 네 악몽과 충동도 더 커질 테니까.","JPN":"龍血と龍について知るにつれ、お前の悪夢と衝動もさらに強まるだろう。","ENG":"The more you learn about Dragons and Dragon Blood, the stronger your nightmares and vicious impulses will grow.","TWN":"你知道越多龍血和龍的事只會更常做惡夢而已。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨…….","JPN":"それはどういう……","ENG":"What do you mean-","TWN":"有聽沒有懂……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대신 이걸 주지.","JPN":"代わりにこれをやろう。","ENG":"Instead, I'll give you this.","TWN":"雖然不能跟你說太多，但這個給你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"What is this?","TWN":"這是……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네 어머니가 쓰던 칼이다.","JPN":"お前の母親が使っていた刀だ。","ENG":"It's your mother's sword.","TWN":"這是你媽媽用過的劍。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>용아</color>. 지니고 있으면 악몽이 조금은 약해질 거야.","JPN":"名前は<color=#ffd34c>龍牙</color>。持っていれば少しは悪夢が弱まるだろう。","ENG":"Its name is <color=#ffd34c>Dragon Fang</color>. Keep it on your person to alleviate the nightmares.","TWN":"這把劍叫作<color=#ffd34c>龍牙</color>，你帶著它做惡夢的情況應該會好一點。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"물론 완전히 사라지진 않아.","JPN":"もちろん、完全に消えやしない。","ENG":"Of course, it won't get rid of the nightmares completely.","TWN":"只是好一點，不是完全消失。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 그 악몽에 잡아 먹히지 않을 만큼 강해져라.","JPN":"だから、その悪夢に囚われないぐらい強くなれ。","ENG":"So you must become strong enough, until the nightmares can't get you anymore.","TWN":"所以你要變得更強！才不會被惡夢吞噬掉。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"싸우는 법이라면……. 내가 가르쳐 주마.","JPN":"戦い方なら……私が教えてやる。","ENG":"As for how to fight… That I can teach you.","TWN":"至於怎麼變強……我會教你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"알겠어요.","JPN":"わかりました。","ENG":"Understood.","TWN":"好！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 이 칼…… 칼집은 없나요?","JPN":"でもこの刀……鞘はないんですか？","ENG":"By the way, does this sword come with a scabbard?","TWN":"不過……這把劍沒有劍鞘嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……있었지. 아주 오래 전에는.","JPN":"……あったな。遠い昔には。","ENG":"It did… A long, long time ago.","TWN":"……很久以前有。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언젠가 네가 자신의 운명을 극복할 만큼 강해진다면…….","JPN":"いつかお前が、自分の運命を乗り越えるほど強くなったら……","ENG":"One day, when you become strong enough to overcome your own fate…","TWN":"等你強到可以勝過命運時……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다시 되찾을 수도 있을지도.","JPN":"再び取り戻すこともできるかもしれないな。","ENG":"You might be able to get it back.","TWN":"或許可以失而復得。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……이봐, 소년. 일어나도록.","JPN":"……おい、少年。起きろ。","ENG":"…Oy, lad. Get up.","TWN":"……喂，你醒一醒！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"으음……?","JPN":"ううん……？","ENG":"Hmm…?","TWN":"嗯……？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"적응이 빠르군. 이런 상황에서도 잠을 자다니 말이야.","JPN":"適応力が高いな。こんな状況でも寝られるとは。","ENG":"I must say, you demonstrate the most uncanny ability to acclimate. Falling asleep, even amidst such discomfort.","TWN":"你還適應得真快，這種情況下也能睡。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 잘 모르시는 모양인데 원래 사람은 피를 뽑으면 잠이 오는 법입니다.","JPN":"ハハ、やられた側じゃないと\\nわからないかもですが、元々人間は血を抜かれると眠くなるものですよ？","ENG":"Haha, in case you didn't know, people tend to fall asleep if you draw their blood.","TWN":"哈哈～你不知道嗎？人抽完血本來就會想睡覺啊。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 칼을 돌려주시면 직접 경험시켜 드릴 수도 있는데 말이죠.","JPN":"僕の剣を返してくれたら、直接体験させてあげることもできるのですが。","ENG":"I could show you what that's like, if you return my sword to me.","TWN":"你把劍還給我的話，我是可以讓你體驗一下。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흥미롭지만 사양하지. 내 피는 평민들처럼 함부로 흘리고 다닐 것이 아니니까.","JPN":"興味深い話だが遠慮しておこう。私の血は平民のように、むやみに流していいものではないからな。","ENG":"As fascinating as that sounds, I must decline. My blood isn't to be squandered like some peasant's.","TWN":"很有趣的提議，但不用客氣了。我的血很尊貴，和死老百姓的血不一樣。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 보기보다 인간관계가 좋은 편이더군.","JPN":"ところで、意外と人間関係が良好だったようだな。","ENG":"By the by, it appears you have managed your relationships surprisingly well.","TWN":"不過沒想到你的人緣還不錯嘛！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하는 말을 들어보면 성격이 그리 좋아 보이지는 않는데 말이야.","JPN":"今までの発言を聞く限り、あまり性格がよさそうには思えないが。","ENG":"Especially given your most aggravatingly insolent manner of speech.","TWN":"聽你說話的方式，感覺不出來你個性很好啊？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……무슨 뜻이죠?","JPN":"……どういう意味ですか？","ENG":"…What do you mean?","TWN":"……怎麼突然關心起我的人緣？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"널 구하기 위해 꽤 많은 인원들이 이곳으로 오고 있다는 말이다.","JPN":"貴様を救うために大勢がここに来ているということだ。","ENG":"I mean that there's a considerable number of individuals on their way to rescue you.","TWN":"因為有好多人要來這裡救你。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 스승인 발키리도, 그리고 저주받은 늑대도.","JPN":"お前の師匠であるヴァルキリーも、そして呪われた狼も。","ENG":"Including that Valkyrie, Master of yours, and the Cursed Wolf.","TWN":"像是你的女武神師父，還有受到詛咒的狼。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……저주받은 늑대? 설마 미나 양 말인가요?","JPN":"……呪われた狼？　もしかしてミナさんのことですか？","ENG":"…Cursed Wolf? You mean Mina?","TWN":"……受到詛咒的狼？你是說米娜嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 우리 불민한 성녀님이 뿌려 둔 미끼가 제법 먹음직스러웠나 보더군.","JPN":"うむ。我が不敏な聖女様が撒いたエサが相当美味いようだ。","ENG":"Aye. Apparently the bait laid by our obtuse Saintess was rather appealing to them.","TWN":"是啊，看來我們聖女設下的誘餌很有效呢！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이번 세계는 따분하기만 할 줄 알았는데, 오랜만에 재미있는 장면을 볼 수 있겠어.","JPN":"此度の世界は退屈だと思っていたが、久しぶりに面白いものが見られそうだ。","ENG":"I thought this world would offer nothing but ennui, but this should be most entertaining for a change.","TWN":"原本還覺得這次的世界很無聊，終於要來點好玩的了。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……당신들이 스승님과 모종의 악연이 있다는 건 짐작하고 있었습니다.","JPN":"……あなたたちと師匠の間に何らかの因縁があることは推察していました。","ENG":"I've had a hunch that there's quite a history between you all and the Master.","TWN":"……我猜到你們和師父有些過節，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 어째서 미나 양을 노리는 거죠?","JPN":"しかし、なぜミナさんを狙うんですか？","ENG":"But why are you after Mina?","TWN":"但為什麼要牽扯到米娜呢？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"단순히 클리포트 인자를 가지고 있기 때문이라면…….","JPN":"単にクリフォト・ファクターの所持者というのが理由なら……","ENG":"If it's simply because she's got the Qliphoth Factor…","TWN":"難道是因為她有卡巴拉因子嗎……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니야. 그게 아니지. 정말 아무것도 모르는군.","JPN":"違う、そうではない。本当に何も知らないようだな。","ENG":"No. Not at all. You really don't have a clue, do you?","TWN":"才不是，你果真是一無所知呢！"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하긴 그 이방인 녀석도 그렇게 말했었지.","JPN":"まあ、あの異邦人もそう言っていたが。","ENG":"I suppose that other outsider fool said the same thing.","TWN":"也是，那個外邦人也是這麼說的。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너, 네 부모가 죽은 이유를 찾고 있다면서?","JPN":"貴様は、自分の両親が死んだ理由を探していると聞いた。","ENG":"You're seeking the reason behind the death of your parents, are you not?","TWN":"我聽說，你想找出你父母的死因？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"왜 루크레시아가 널 선택했는지 알 것 같군.","JPN":"なぜルクレシアが貴様を選んだのかわかった。","ENG":"I'm beginning to understand why Lucrecia chose you.","TWN":"我大概知道露可蕾西亞為什麼會找上你了。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 멍청한 성녀는 아마도 너에게서 자신의 과거를 겹쳐 봤겠지.","JPN":"あの愚かな聖女は、おそらく貴様に自分の過去を重ねたのだろう。","ENG":"That dolt of a Saintess probably saw her own past self in you.","TWN":"她應該是在你身上看到過去的她吧？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……그게 무슨 뜻이죠?","JPN":"……それはどういう意味ですか？","ENG":"…What is that supposed to mean?","TWN":"……這是什麼意思？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"Well…","TWN":"意思就是……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그만두시죠.","JPN":"おやめください。","ENG":"That's enough, sire.","TWN":"請適可而止。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"남의 뒷이야기나 속삭이는 건 황족의 체통에 어울리지 않는 일 아닌가요?","JPN":"裏で他者の話をするのは、皇族の振る舞いとしてふさわしくないのでは？","ENG":"Isn't it unbecoming for royalty to gossip about others behind their backs?","TWN":"在別人的背後說人閒話似乎有失皇族的體統？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하하. 뭘 모르는군, 루크레시아.","JPN":"ハハハ。わかっていないな、ルクレシア。","ENG":"Hahaha... You have no idea, Lucrecia.","TWN":"哈哈哈～你好像搞不清楚，露可蕾西亞。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"날조된 소문을 퍼트리는 것도 귀족의 신성한 의무 중 하나다.","JPN":"ねつ造された噂を広めることも貴族の神聖な義務の一つだ。","ENG":"Spreading false rumors is one of the sacred duties of nobility.","TWN":"散播假消息也是皇族的神聖任務之一。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"천한 노예 출신인 넌 모르겠지만 말이야.","JPN":"卑しい奴隷出身の貴様にはわからないだろうが。","ENG":"A lowly former slave like you wouldn't understand, of course.","TWN":"身為卑賤的奴隸，你可能不太知道這些。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 좋다. 즐거운 구경을 하려면 나도 이쯤에서 한 발 물러서야겠지.","JPN":"まあ、いい。見物を楽しむには、私もこの辺で一歩退いておかなければな。","ENG":"Very well. I suppose I should take a step back if I am to fully enjoy the show.","TWN":"好吧！我就先退一步吧，畢竟我還想看好戲呢～"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"기대하고 있다. 날 실망시키지 말도록.","JPN":"期待している。くれぐれも私を失望させないように。","ENG":"I'm looking most forward to it. Do not let me down.","TWN":"我很期待喔，千萬別讓我失望。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 소년, 너에게 주어진 두 번째 기회다. 놓치지 마라.","JPN":"そして少年、貴様に与えられた二度目の機会だ。逃がすなよ。","ENG":"And lad, this is your second chance. Don't miss it.","TWN":"還有你，我再給你第二次機會，這次不要再錯過囉。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"두 번째 기회라……. 대체 무슨 말인지 모르겠네요.","JPN":"二度目の機会……いったいどういう意味なのかわかりませんね。","ENG":"Second chance…? I have no idea what that's supposed to mean.","TWN":"第二次機會……到底是什麼機會？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"오늘이 가기 전에 당신은 진실을 알게 될 겁니다.","JPN":"今日が終わる前に、あなたは真実を知ることになるでしょう。","ENG":"You will learn the truth before the day is over.","TWN":"今天結束前你就會知道真相。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신과 당신의 부모, 그리고 당신의 혈통에 흐르는 모든 진실을.","JPN":"あなたとあなたの親、そしてあなたの血統に流れるすべての真実を。","ENG":"The truth about you, your parents, and your bloodline.","TWN":"包括你和你的父母，還有你的血統。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러고 전 당신에게 기회를 드릴 겁니다.","JPN":"そして私はあなたに機会を差し上げるつもりです。","ENG":"And I will give you a chance.","TWN":"所以我要給你機會，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신에게 이 비참한 운명을 부여한 자에게 복수하고…….","JPN":"あなたへ悲惨な運命を与えた者に復讐して……","ENG":"A chance to take vengeance on the one who thrust this tragic fate upon you...","TWN":"向把如此悲慘的命運加諸在你身上的人報仇……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"진정한 구원을 찾을 기회를 말이죠.","JPN":"真の救いを求める機会を。","ENG":"And find true salvation.","TWN":"也就是真正得著救贖的機會。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 또 그 용이 되라는 소린가요?","JPN":"ハハ、またその龍になれってことですか？","ENG":"Haha, are you trying to convince me to become a Dragon again?","TWN":"哈哈～又是要我變成龍嗎？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"죄송하지만 전 지금의 저한테 만족하고 있어서요.","JPN":"申し訳ありませんが、僕は今の自分に満足しています。","ENG":"Sorry, but I'm quite content with who I am right now.","TWN":"不好意思，我對於現在的我感到很滿意，"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"딱히 하고 싶지도 않은 복수를 위해 정체도 모를 존재가 되고 싶지는 않은데요.","JPN":"別にしたくもない復讐のために、正体もわからない存在にはなりたくないですね。","ENG":"I'd rather not turn into some mystery monster just so that I can have some revenge I don't even want.","TWN":"沒有想把自己弄得人不像人鬼不像鬼，然後再搞什麼報仇。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 후회를 돌이킬 기회는 어떻습니까?","JPN":"ならば後悔を取り戻す機会、と言えばどうでしょうか？","ENG":"Then how about a chance to undo your regret?","TWN":"那如果是能夠扭轉過去的機會呢？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"예를 들어……","JPN":"例えば……","ENG":"For instance...","TWN":"譬如說……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"번뇌로 인한 광기를 이기지 못해 살해당한, 당신의 부모님을 구원할 수 있다거나.","JPN":"煩悩による狂気に耐え切れず殺された、あなたの両親を救えるとか。","ENG":"You could save your parents, who were only killed because they could not overcome their madness from Kleshas.","TWN":"譬如說救贖因為煩惱而走火入魔，最後遭到殺害的父母親？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……は？","ENG":"…What did you say?","TWN":"……你說什麼？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"선택은 당신의 몫입니다, 소년.","JPN":"選択はあなた次第です、少年よ。","ENG":"The choice is yours, lad.","TWN":"選擇權在你的手上。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"황태자님의 말씀대로, 부디 이 기회를 놓치지 않길 바라지요.","JPN":"皇太子様のお言葉どおり、この機会を逃さないよう祈るばかりです。","ENG":"I hope you do not miss this chance, as the Crown Prince has said.","TWN":"就如皇太子所言，希望你不要錯失良機。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};